"use client"

import { Bell, Calendar, Stethoscope } from 'lucide-react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import React from 'react'
import { Button } from '../ui/button';
import { Badge } from '../ui/badge';
import { DropdownMenu, DropdownMenuTrigger } from '../ui/dropdown-menu';

interface HeadersProp {
    showDashboardNav?: boolean
}

interface NavigationItem {
    label: string;
    icon: React.ComponentType<any>;
    href: string;
    active: boolean

}

function Headers({ showDashboardNav = false }: HeadersProp) {

    const user = {
        type: "patient"
    }

    const pathname = usePathname();

    const isAuthenticated = true;

    const getDashboardNavigation = (): NavigationItem[] => {
        if (!user || !showDashboardNav) {
            return [];
        }

        if (user?.type === "patient") {
            return [
                {
                    label: "Appointments",
                    icon: Calendar,
                    href: "/patient/dashboard",
                    active: pathname?.includes("/patient/dashboard") || false
                }
            ]
        } else if (user?.type === "doctor") {
            return [
                {
                    label: "Dashboard",
                    icon: Calendar,
                    href: "/doctor/dashboard",
                    active: pathname?.includes("/doctor/dashboard") || false
                },
                {
                    label: "Appointments",
                    icon: Calendar,
                    href: "/doctor/appointments",
                    active: pathname?.includes("/doctor/appointments") || false
                }
            ]
        }

        return []

    }


    return (
        <header className="border-b bg-white/95 backdrop:blur-sm fixed 
         top-0 left-0 right-0 z-50">

            <div className="container mx-auto px-4 h-16 flex items-center justify-between">

                {/* left side => logo + navigation */}
                <div className="flex items-center space-x-8">
                    <Link href="/" className="flex items-center space-x-2">
                        <div className="w-8 h-8 bg-gradient-to-br from-blue-600
                         to-blue-700 rounded-lg flex items-center justify-center">
                            <Stethoscope className="w-5 h-5 text-white" />
                        </div>

                        <div className="text-2xl font-bold bg-gradient-to-br from-blue-600
                         to-blue-800  bg-clip-text text-transparent">
                            Medicare+
                        </div>
                    </Link>

                    {/* dashboard navigation */}
                    {
                        isAuthenticated && showDashboardNav && (
                            <nav className="hidden md:flex items-center space-x-6">
                                {getDashboardNavigation().map((item) => (
                                    <Link
                                        key={item.href}
                                        href={item.href}
                                        className={`flex items-center space-x-1 transition-colors ${item.active
                                            ? "text-blue-600 font-semibold"
                                            : "text-gray-600 hover:text-blue-600"
                                            }`}
                                    >
                                        <item.icon className="w-4 h-4" />
                                        <span className="text-sm font-medium">
                                            {item.label}
                                        </span>
                                    </Link>
                                ))}
                            </nav>
                        )
                    }
                </div>

                {/* right side */}
                {
                    isAuthenticated && showDashboardNav ? (
                        <div className='flex items-center space-x-4'>
                            <Button variant="ghost" size="sm" className='relative'>
                                <Bell className='w-5 h-5' />
                                <Badge className='absolute -top-1 -right-1 w-5 h-5 text-xs
                                 bg-red-500 hover:bg-red-600'>
                                    4
                                </Badge>
                            </Button>

                            <DropdownMenu>
                                <DropdownMenuTrigger asChild>

                                </DropdownMenuTrigger>
                            </DropdownMenu>
                        </div>

                    ) : (
                        <div className='flex items-center space-x-3'>
                            {
                                !isAuthenticated ? (
                                    <div>
                                        <link href='/login/patient'>
                                            <Button
                                                variant="ghost"
                                                className='text-blue-900 font-medium
                                                 hover:text-blue-700'
                                            >
                                                Login
                                            </Button>
                                        </link>

                                        <link
                                            href='/signup/patient'
                                            className="hidden md:block"
                                        >
                                            <Button
                                                variant="ghost"
                                                className='bg-gradient-to-r from-blue-600
                                                 to-blue-700  font-medium hover:from-blue-700
                                                  hover:to-blue-800 rounded-full px-6'
                                            >
                                                Book Consultation
                                            </Button>

                                        </link>
                                    </div>
                                ) : (
                                    <div className='flex items-center space-x-4'>
                                        <span className='hidden md:block text-sm
                                         text-gray-700 font-medium whitespace-nowrap'
                                        >
                                            Welcome,&nbsp;{user?.name}
                                        </span>

                                        <link href={`/${user?.type}/dashboard`}>
                                            <Button
                                                variant="ghost"
                                                className='text-blue-900 font-medium
                                                 hover:text-blue-700'
                                            >
                                                Dashboard
                                            </Button>
                                        </link>

                                    </div>
                                )
                            }

                        </div>
                    )
                }
            </div>

        </header>
    )
}

export default Headers;
